func:
var sqlInfo = (msg.payload || [])[0] || {};
msg.payload = {
  status: 'ok',
  service: 'despachos-pendientes',
  timestamp: new Date().toISOString(),
  version: '1.3.0',
  sql: {
    server: sqlInfo.server_name || 'n/a',
    database: sqlInfo.db_name || 'n/a',
    user: sqlInfo.login_user || 'n/a',
    serverTime: sqlInfo.server_time || 'n/a'
  }
};
return msg;

var days = parseInt(msg.req.query.days) || 30;
if (days < 1) days = 1;
if (days > 365) days = 365;

var uuid = Date.now().toString(36).toUpperCase().slice(-4) +
  Math.random().toString(36).substring(2, 6).toUpperCase() +
  Math.random().toString(36).substring(2, 6).toUpperCase();

msg._trace = { uuid: uuid, days: days };

msg.payload = "SELECT pr.remito, pr.fecha, pr.razonsocial AS cliente, pr.cuit, " +
  "pr.domicilio, pr.localidad, pr.provincia, " +
  "pr.transportista, pr.chofer, pr.patente, pr.chasis, " +
  "pr.numero_pesada AS guia, pr.usuario, pr.creado, pr.observaciones, " +
  "pr.destino, pi.descripcion AS producto, pi.cantidad, " +
  "pi.unidamedida2 AS unidad, pi.cantidad2, pi.precio, pi.orden " +
  "FROM pr_ezi_remitos pr " +
  "INNER JOIN pr_ezi_remitos_items pi ON pr.remito = pi.Remito " +
  "WHERE pr.factura IS NULL " +
  "AND pr.fecha >= DATEADD(DAY, -" + days + ", GETDATE()) " +
  "ORDER BY pr.fecha DESC, pr.remito, pi.orden";

node.warn('[Despachos] ' + uuid + ' days=' + days);
return msg;

var rows = msg.payload || [];
var uuid = msg._trace ? msg._trace.uuid : 'N/A';
var days = msg._trace ? msg._trace.days : 30;

var remitos = {};
var clientesSet = {};

rows.forEach(function(row) {
  var key = row.remito;
  if (!remitos[key]) {
    remitos[key] = {
      remito: row.remito, fecha: row.fecha, cliente: row.cliente, cuit: row.cuit,
      domicilio: row.domicilio, localidad: row.localidad, provincia: row.provincia,
      transportista: row.transportista ? row.transportista.trim() : '',
      chofer: row.chofer ? row.chofer.trim() : '',
      patente: row.patente ? row.patente.trim() : '',
      chasis: row.chasis ? row.chasis.trim() : '',
      guia: row.guia, usuario: row.usuario, creado: row.creado,
      observaciones: row.observaciones, destino: row.destino,
      items: [], totalItems: 0, totalImporte: 0
    };
  }
  remitos[key].items.push({
    orden: row.orden, producto: row.producto, cantidad: row.cantidad,
    unidad: row.unidad, cantidad2: row.cantidad2, precio: row.precio,
    total: (row.cantidad || 0) * (row.precio || 0)
  });
  remitos[key].totalItems++;
  remitos[key].totalImporte += (row.cantidad || 0) * (row.precio || 0);
  clientesSet[row.cliente] = true;
});

var data = Object.keys(remitos).map(function(key) {
  var r = remitos[key];
  var firstItem = r.items[0] || {};
  return {
    remito: r.remito, fecha: r.fecha, cliente: r.cliente, cuit: r.cuit,
    destino: r.localidad ? r.localidad + (r.provincia ? ', ' + r.provincia : '') : '-',
    producto: firstItem.producto, cantidad: firstItem.cantidad, unidad: firstItem.unidad,
    cantidad2: firstItem.cantidad2, precio: firstItem.precio, totalItem: firstItem.total,
    totalImporte: r.totalImporte, itemsCount: r.totalItems,
    transportista: r.transportista, chofer: r.chofer, patente: r.patente,
    chasis: r.chasis, guia: r.guia, observaciones: r.observaciones
  };
});

var totalBolsas = 0, totalToneladas = 0, totalImporte = 0;
var prodCounts = {};
data.forEach(function(item) {
  totalImporte += item.totalImporte || 0;
  if (item.unidad === 'Bolsa' || item.unidad === 'Bolsa(s)') totalBolsas += item.cantidad || 0;
  if (item.unidad === 'Tonelada' || item.unidad === 'TN') totalToneladas += item.cantidad2 || 0;
  prodCounts[item.producto] = (prodCounts[item.producto] || 0) + 1;
});

msg.payload = {
  metadata: { runUuid: uuid, timestamp: new Date().toISOString(), source: 'CORONA.pr_ezi_remitos', filterDays: days },
  resumen: {
    totalRemitos: data.length, totalClientes: Object.keys(clientesSet).length,
    totalBolsas: totalBolsas, totalToneladas: totalToneladas, totalImporte: totalImporte,
    productos: prodCounts
  },
  data: data
};
return msg;

var remito = msg.req.params.remito;
if (!remito) {
  msg.statusCode = 400;
  msg.payload = { error: 'Falta parámetro remito' };
  return msg;
}
msg._trace = { remito: remito };
msg.payload = "SELECT pr.*, pi.descripcion AS producto, pi.cantidad, " +
  "pi.unidamedida2 AS unidad, pi.cantidad2, pi.precio, pi.orden " +
  "FROM pr_ezi_remitos pr " +
  "INNER JOIN pr_ezi_remitos_items pi ON pr.remito = pi.Remito " +
  "WHERE pr.remito = '" + remito.replace(/'/g, "''") + "'";
return msg;

var rows = msg.payload || [];
if (!rows.length) {
  msg.statusCode = 404;
  msg.payload = { error: 'Remito no encontrado' };
  return msg;
}
var first = rows[0];
var detalle = {
  remito: first.remito, fecha: first.fecha, cliente: first.razonsocial, cuit: first.cuit,
  domicilio: first.domicilio, localidad: first.localidad, provincia: first.provincia,
  destino: first.destino,
  transportista: first.transportista ? first.transportista.trim() : '',
  chofer: first.chofer ? first.chofer.trim() : '',
  dniChofer: first.dniChofer || first.dni || '',
  patente: first.patente ? first.patente.trim() : '',
  chasis: first.chasis ? first.chasis.trim() : '',
  guia: first.numero_pesada, usuario: first.usuario, creado: first.creado,
  observaciones: first.observaciones, factura: first.factura,
  items: [], totalImporte: 0
};
rows.forEach(function(row) {
  var total = (row.cantidad || 0) * (row.precio || 0);
  detalle.items.push({
    orden: row.orden, producto: row.producto, cantidad: row.cantidad,
    unidad: row.unidad, cantidad2: row.cantidad2, precio: row.precio, total: total
  });
  detalle.totalImporte += total;
});
msg.payload = detalle;
return msg;

// 1. Validar y armar EXEC pr_ezi_vincular_factura
// Middleware ERP: SP con validación + auditoría + transacción
var remito = msg.req.params.remito;
var factura = msg.req.body ? msg.req.body.factura : null;

if (!remito) {
  msg.statusCode = 400;
  msg.payload = { success: false, error: 'Falta parámetro remito' };
  return msg;
}
if (!factura || factura.trim() === '') {
  msg.statusCode = 400;
  msg.payload = { success: false, error: 'Falta número de factura' };
  return msg;
}

// Generar UUID de trazabilidad
var uuid = Date.now().toString(36).toUpperCase().slice(-4) +
  Math.random().toString(36).substring(2, 6).toUpperCase() +
  Math.random().toString(36).substring(2, 6).toUpperCase();

var remitoSafe = remito.replace(/'/g, "''");
var facturaSafe = factura.trim().replace(/'/g, "''");

msg._trace = { remito: remitoSafe, factura: facturaSafe, uuid: uuid };

// SP con OUTPUT params + SELECT final para que MSSQL node devuelva resultado
msg.payload = "DECLARE @success BIT, @mensaje NVARCHAR(200), @audit_id INT; "
  + "EXEC dbo.pr_ezi_vincular_factura "
  + "  @remito = '" + remitoSafe + "', "
  + "  @factura = '" + facturaSafe + "', "
  + "  @usuario = 'Node-RED', "
  + "  @run_uuid = '" + uuid + "', "
  + "  @success = @success OUTPUT, "
  + "  @mensaje = @mensaje OUTPUT, "
  + "  @audit_id = @audit_id OUTPUT; "
  + "SELECT @success AS success, @mensaje AS mensaje, @audit_id AS audit_id;";

node.warn('[Despachos] Vincular factura ' + facturaSafe + ' a remito ' + remitoSafe + ' [' + uuid + ']');
return msg;

// 2. Procesar resultado del SP pr_ezi_vincular_factura + preparar auditoría MySQL
var row = (msg.payload || [])[0] || {};

// Construir consulta de auditoría MySQL (común a éxito y fallo)
var uuid = msg._trace.uuid || 'N/A';
var remitoSafe = (msg._trace.remito || '').replace(/'/g, "\\'");
var facturaSafe = (msg._trace.factura || '').replace(/'/g, "\\'");

if (row.success === true || row.success === 1 || row.success === "1") {
  node.warn('[Despachos] Vinculación exitosa — '
    + 'remito ' + msg._trace.remito
    + ' ← factura ' + msg._trace.factura
    + ' [sp_audit_id=' + (row.audit_id || 0) + ']');

  // msg1: HTTP response
  var msg1 = { payload: { success: true, remito: msg._trace.remito,
      factura: msg._trace.factura, auditId: row.audit_id || 0,
      mensaje: row.mensaje || 'Vinculado correctamente' } };

  // msg2: MySQL audit (fire-and-forget)
  var msg2 = { topic: "INSERT INTO despachos_audit_factura "
      + "(run_uuid, remito, factura, usuario, aplicacion, accion, resultado, mensaje, sp_audit_id) "
      + "VALUES ('" + uuid + "', '" + remitoSafe + "', '" + facturaSafe + "', "
      + "'Node-RED', 'DespachosApp', 'VINCULAR', 1, "
      + "'Vinculado correctamente', " + (row.audit_id || 0) + ")" };

  return [msg1, msg2];
}

// Fallo validado por el SP
msg.statusCode = 409;
var errorMsg = (row.mensaje || 'No se pudo vincular').replace(/'/g, "\\'").substring(0, 200);

var msg1 = { statusCode: 409,
  payload: { success: false, remito: msg._trace.remito,
    error: row.mensaje || 'No se pudo vincular la factura',
    auditId: row.audit_id || 0 } };

var msg2 = { topic: "INSERT INTO despachos_audit_factura "
    + "(run_uuid, remito, factura, usuario, aplicacion, accion, resultado, mensaje, sp_audit_id) "
    + "VALUES ('" + uuid + "', '" + remitoSafe + "', '" + facturaSafe + "', "
    + "'Node-RED', 'DespachosApp', 'VINCULAR', 0, "
    + "'" + errorMsg + "', " + (row.audit_id || 0) + ")" };

return [msg1, msg2];

var days = parseInt(msg.req.query.days) || 30;
if (days < 1) days = 1;
if (days > 365) days = 365;
msg._trace = { days: days };

msg.payload = "SELECT " +
  "COUNT(DISTINCT pr.remito) AS totalRemitos, " +
  "COUNT(DISTINCT pr.razonsocial) AS totalClientes, " +
  "SUM(CASE WHEN pi.unidamedida2 = 'Bolsa' OR pi.unidamedida2 = 'Bolsa(s)' THEN pi.cantidad ELSE 0 END) AS totalBolsas, " +
  "SUM(CASE WHEN pi.unidamedida2 = 'Tonelada' OR pi.unidamedida2 = 'TN' THEN pi.cantidad2 ELSE 0 END) AS totalToneladas, " +
  "SUM(pi.cantidad * pi.precio) AS totalImporte, " +
  "COUNT(DISTINCT pi.descripcion) AS totalProductos " +
  "FROM pr_ezi_remitos pr " +
  "INNER JOIN pr_ezi_remitos_items pi ON pr.remito = pi.Remito " +
  "WHERE pr.factura IS NULL " +
  "AND pr.fecha >= DATEADD(DAY, -" + days + ", GETDATE())";
return msg;

// Guardar resultado KPIs antes de pisar msg.payload
msg.payload2 = msg.payload;

// Segunda consulta: conteo por producto
msg.payload = "SELECT pi.descripcion AS producto, COUNT(DISTINCT pr.remito) AS cantidad " +
  "FROM pr_ezi_remitos pr " +
  "INNER JOIN pr_ezi_remitos_items pi ON pr.remito = pi.Remito " +
  "WHERE pr.factura IS NULL " +
  "AND pr.fecha >= DATEADD(DAY, -" + msg._trace.days + ", GETDATE()) " +
  "GROUP BY pi.descripcion ORDER BY cantidad DESC";
return msg;

var row = (msg.payload2 || [])[0] || {};
var productos = (msg.payload || []).reduce(function(acc, p) {
  acc[p.producto] = p.cantidad;
  return acc;
}, {});

msg.payload = {
  totalRemitos: row.totalRemitos || 0,
  totalClientes: row.totalClientes || 0,
  totalBolsas: row.totalBolsas || 0,
  totalToneladas: row.totalToneladas || 0,
  totalImporte: row.totalImporte || 0,
  productos: productos
};
return msg;

msg.statusCode = msg.statusCode || 500;
var errMsg = 'Error interno del servidor';
if (msg.payload) {
  if (typeof msg.payload === 'string') errMsg = msg.payload;
  else if (msg.payload.message) errMsg = msg.payload.message;
  else if (msg.payload.error) errMsg = msg.payload.error;
  else errMsg = JSON.stringify(msg.payload).substring(0, 500);
}
if (msg.error && msg.error.message) errMsg = msg.error.message;
else if (typeof msg.error === 'string') errMsg = msg.error;
msg.payload = { error: errMsg, code: msg.statusCode };
node.warn('[Despachos] Error ' + msg.statusCode + ': ' + errMsg);
return msg;

// Fire-and-forget: solo loguea resultado de la auditoría MySQL
if (msg.topic === 'audit') {
  node.log('[Despachos] Auditoría MySQL registrada');
}
// No modifica msg — la respuesta HTTP ya se envió por la rama principal
return msg;

// 1. Iniciar sync — generar UUID y preparar parámetros
var days = parseInt((msg.req.body || {}).days) || 30;
if (days < 1) days = 1;
if (days > 365) days = 365;

var uuid = Date.now().toString(36).toUpperCase().slice(-4) +
  Math.random().toString(36).substring(2, 6).toUpperCase() +
  Math.random().toString(36).substring(2, 6).toUpperCase();

msg._trace = { uuid: uuid, days: days, startedAt: new Date().toISOString() };

node.warn('[Despachos] Sync Sheets iniciado [' + uuid + '] days=' + days);

// Query SQL Server — mismos datos que GET /pendientes
msg.payload = "SELECT pr.remito, pr.fecha, pr.razonsocial AS cliente, pr.cuit, "
  + "pr.domicilio, pr.localidad, pr.provincia, "
  + "pr.transportista, pr.chofer, pr.patente, pr.chasis, "
  + "pr.numero_pesada AS guia, pr.usuario, pr.creado, pr.observaciones, "
  + "pr.destino, pi.descripcion AS producto, pi.cantidad, "
  + "pi.unidamedida2 AS unidad, pi.cantidad2, pi.precio, pi.orden "
  + "FROM pr_ezi_remitos pr "
  + "INNER JOIN pr_ezi_remitos_items pi ON pr.remito = pi.Remito "
  + "WHERE pr.factura IS NULL "
  + "AND pr.fecha >= DATEADD(DAY, -" + days + ", GETDATE()) "
  + "ORDER BY pr.fecha DESC, pr.remito, pi.orden";

return msg;

// 2. Transformar datos SQL Server → formato MySQL cache + Sheets
var rows = msg.payload || [];
var uuid = msg._trace.uuid;
var days = msg._trace.days;

// Agrupar por remito (misma lógica que GET /pendientes)
var remitos = {};
var clientesSet = {};

rows.forEach(function(row) {
  var key = row.remito;
  if (!remitos[key]) {
    remitos[key] = {
      remito: row.remito, fecha: row.fecha, cliente: row.cliente, cuit: row.cuit,
      domicilio: row.domicilio, localidad: row.localidad, provincia: row.provincia,
      transportista: row.transportista ? row.transportista.trim() : '',
      chofer: row.chofer ? row.chofer.trim() : '',
      patente: row.patente ? row.patente.trim() : '',
      guia: row.guia, usuario: row.usuario, creado: row.creado,
      observaciones: row.observaciones, destino: row.destino,
      items: [], totalItems: 0, totalImporte: 0
    };
    clientesSet[row.cliente] = true;
  }
  remitos[key].items.push({
    orden: row.orden, producto: row.producto, cantidad: row.cantidad,
    unidad: row.unidad, cantidad2: row.cantidad2, precio: row.precio,
    total: (row.cantidad || 0) * (row.precio || 0)
  });
  remitos[key].totalItems++;
  remitos[key].totalImporte += (row.cantidad || 0) * (row.precio || 0);
});

// Preparar INSERTs para MySQL cache
var inserts = [];
var totalBolsas = 0, totalToneladas = 0, totalImporte = 0;
var prodCounts = {};

Object.keys(remitos).forEach(function(key) {
  var r = remitos[key];
  var firstItem = r.items[0] || {};
  var prod = firstItem.producto || '';

  // KPIs
  totalImporte += r.totalImporte || 0;
  if (firstItem.unidad === 'Bolsa' || firstItem.unidad === 'Bolsa(s)') totalBolsas += firstItem.cantidad || 0;
  if (firstItem.unidad === 'Tonelada' || firstItem.unidad === 'TN') totalToneladas += firstItem.cantidad2 || 0;
  prodCounts[prod] = (prodCounts[prod] || 0) + 1;

  // Escapar strings para MySQL
  var esc = function(s) {
    if (!s) return 'NULL';
    return "'" + String(s).replace(/\\/g, "\\\\").replace(/'/g, "\\'").substring(0, 200) + "'";
  };

  inserts.push(
    "INSERT INTO despachos_pendientes_cache "
    + "(remito, fecha, cliente, cuit, producto, cantidad, unidad, precio, total, transportista, sync_run_uuid) "
    + "VALUES ("
    + esc(r.remito) + ", "
    + (r.fecha ? "'" + r.fecha + "'" : 'NULL') + ", "
    + esc(r.cliente) + ", "
    + esc(r.cuit) + ", "
    + esc(prod) + ", "
    + (firstItem.cantidad || 0) + ", "
    + esc(firstItem.unidad) + ", "
    + (firstItem.precio || 0) + ", "
    + (firstItem.total || 0) + ", "
    + esc(r.transportista) + ", "
    + esc(uuid) + ")"
    + " ON DUPLICATE KEY UPDATE "
    + "fecha=VALUES(fecha), cliente=VALUES(cliente), cuit=VALUES(cuit), "
    + "producto=VALUES(producto), cantidad=VALUES(cantidad), unidad=VALUES(unidad), "
    + "precio=VALUES(precio), total=VALUES(total), transportista=VALUES(transportista), "
    + "sync_run_uuid=VALUES(sync_run_uuid)"
  );
});

// Guardar metadata para el response y el sync_state
msg._kpi = {
  totalRemitos: Object.keys(remitos).length,
  totalClientes: Object.keys(clientesSet).length,
  totalBolsas: totalBolsas,
  totalToneladas: totalToneladas,
  totalImporte: totalImporte,
  productos: prodCounts
};

// Guardar los INSERTs para el paso MySQL (msg.mysqlPayload)
msg.mysqlPayload = inserts;
msg.payload = rows; // mantener rows originales por si se necesita

node.warn('[Despachos] Sync: ' + inserts.length + ' remitos para INSERT en MySQL cache');

return msg;

// 3. Preparar push a Google Sheets (vía SheetDB o Google Apps Script webapp)
//    Configurar GOOGLE_SHEETS_WEBHOOK en settings.js de Node-RED
var sheetsUrl = env.get("DESPACHOS_SHEETS_WEBHOOK") || "";

if (!sheetsUrl) {
  // Sin webhook configurado — solo MySQL cache, reportar skip
  node.warn('[Despachos] Sheets webhook no configurado (DESPACHOS_SHEETS_WEBHOOK). Solo MySQL cache.');
  msg._sheetsStatus = "skipped";
  msg._sheetsMessage = "Webhook no configurado. Solo MySQL cache actualizado.";
  return msg;
}

// Preparar payload para Sheets
var kpi = msg._kpi || {};
msg.url = sheetsUrl;
msg.method = "POST";
msg.headers = { "Content-Type": "application/json" };

// Formato: filas para SheetDB o Google Apps Script
msg.payload = {
  action: "sync_pendientes",
  metadata: {
    runUuid: msg._trace.uuid,
    timestamp: new Date().toISOString(),
    source: "CORONA.pr_ezi_remitos",
    filterDays: msg._trace.days
  },
  resumen: kpi,
  data: [] // Se completa abajo
};

// Reconstruir data desde mysqlPayload (INSERTs ya ejecutados)
// Usamos las filas originales para armar el payload de Sheets
// (se hace en el siguiente nodo para no duplicar)

return msg;

// 4. Registrar resultado del sync en MySQL + responder al cliente
var kpi = msg._kpi || {};
var uuid = msg._trace.uuid;
var startedAt = msg._trace.startedAt;
var completedAt = new Date().toISOString();
var rowsCount = kpi.totalRemitos || 0;

var sheetsStatus = msg._sheetsStatus || "OK";
var sheetsMsg = msg._sheetsMessage || "";

// Determinar status basado en respuesta del HTTP request
if (msg.payload && msg.payload.error) {
  sheetsStatus = "ERROR";
  sheetsMsg = msg.payload.error;
}

// Preparar INSERT en despachos_sync_state (fire-and-forget vía msg2)
var escMsg = sheetsMsg ? sheetsMsg.replace(/'/g, "\\'").substring(0, 500) : "";
msg.mysqlTopic = "INSERT INTO despachos_sync_state "
  + "(run_uuid, sheet_name, rows_synced, status, error_message, started_at, completed_at) "
  + "VALUES ('" + uuid + "', 'Pendientes', " + rowsCount + ", "
  + "'" + sheetsStatus + "', "
  + (escMsg ? "'" + escMsg + "'" : "NULL") + ", "
  + "'" + startedAt + "', '" + completedAt + "')";

// Responder al cliente con resumen
var responseMsg = {
  payload: {
    success: sheetsStatus === "OK" || sheetsStatus === "skipped",
    runUuid: uuid,
    timestamp: completedAt,
    sheetsStatus: sheetsStatus,
    sheetsMessage: sheetsMsg,
    cacheStatus: "OK",
    resumen: {
      totalRemitos: rowsCount,
      totalClientes: kpi.totalClientes || 0,
      totalBolsas: kpi.totalBolsas || 0,
      totalToneladas: kpi.totalToneladas || 0,
      totalImporte: kpi.totalImporte || 0
    }
  }
};

// msg2: auditoría MySQL (fire-and-forget)
var auditMsg = { topic: msg.mysqlTopic };

node.warn('[Despachos] Sync completado [' + uuid + '] status=' + sheetsStatus + ' rows=' + rowsCount);

return [responseMsg, auditMsg];

// Consultar último estado de sync desde MySQL
msg.topic = "SELECT run_uuid, sheet_name, rows_synced, status, error_message, "
  + "started_at, completed_at "
  + "FROM despachos_sync_state "
  + "ORDER BY started_at DESC LIMIT 5";
return msg;

// Formatear respuesta de estado de sync
var rows = msg.payload || [];

msg.payload = {
  service: "despachos-sheets-sync",
  lastSync: rows.length > 0 ? {
    runUuid: rows[0].run_uuid,
    sheetName: rows[0].sheet_name,
    rowsSynced: rows[0].rows_synced,
    status: rows[0].status,
    errorMessage: rows[0].error_message || null,
    startedAt: rows[0].started_at,
    completedAt: rows[0].completed_at
  } : null,
  recentHistory: rows.map(function(r) { return {
    runUuid: r.run_uuid,
    rowsSynced: r.rows_synced,
    status: r.status,
    completedAt: r.completed_at
  }})
};

return msg;
